import * as XLSX from 'xlsx';
import dayjs from 'dayjs';
import customParseFormat from 'dayjs/plugin/customParseFormat.js';

dayjs.extend(customParseFormat);

export const processCombinedData = (csvData, excelRaw) => {
  // --- 1. PROCESAR EXCEL (EASY DOCKING - UNIDADES FÍSICAS) ---
  const workbook = XLSX.read(excelRaw, { type: 'array' });
  const sheet = workbook.Sheets[workbook.SheetNames[0]];
  const rawMatrix = XLSX.utils.sheet_to_json(sheet, { header: 1 });

  const headers = rawMatrix[3]; // Fila 4 (Headers)
  const dataRows = rawMatrix.slice(4); // Datos

  const easyDockingClean = dataRows.map(row => {
    let obj = {};
    headers.forEach((h, i) => obj[h] = row[i]);
    return obj;
  }).filter(item => 
    item['TIPO DE OP'] === "DESCARGA" && 
    item['ACCION'] === "add"
  );

  // SUMAMOS las piezas del Excel (Lo que entró al Hub)
  const totalPiezasArribadas = easyDockingClean.reduce((acc, curr) => {
    const cant = parseFloat(curr['CANT PAQUETE']) || 0;
    return acc + cant;
  }, 0);

  // --- 2. PROCESAR CSV (TMS - PIEZAS INDIVIDUALES) ---
  // CONTAMOS las filas del CSV (Lo que se procesó en sistema)
  const totalPiezasBipeadas = csvData.filter(d => 
    d['Labeling Date Printed'] && d['Labeling Date Printed'].trim() !== ""
  ).length;

  // --- 3. CÁLCULO DE PENDIENTES ---
  const pendientes = totalPiezasArribadas - totalPiezasBipeadas;

  // --- 4. GRÁFICA (05:00 a 23:00) ---
  const franjas = [];
  for (let i = 5; i <= 23; i++) {
    franjas.push(`${i.toString().padStart(2, '0')}:00`);
  }
  const chartMap = {};
  franjas.forEach(h => chartMap[h] = { hora: h, arribo: 0, bipeo: 0 });

  // Arribos: Sumamos CANT PAQUETE del Excel por hora
  easyDockingClean.forEach(row => {
    if (row['Fecha y hor']) {
      const hora = dayjs(row['Fecha y hor']).format('HH:00');
      if (chartMap[hora]) {
        chartMap[hora].arribo += (parseFloat(row['CANT PAQUETE']) || 0);
      }
    }
  });

  // Bipeos: Contamos filas del CSV por hora
  csvData.forEach(row => {
    const rawDate = row['Labeling Date Printed'];
    if (rawDate) {
      const hora = dayjs(rawDate, "DD/MM/YYYY HH:mm:ss").format('HH:00');
      if (chartMap[hora]) chartMap[hora].bipeo++;
    }
  });

  // --- 5. TABLA DE ARMADO DE HU ---
  const tableData = franjas.map(hora => {
    const bipeadasEnHora = csvData.filter(d => 
      d['Labeling Date Printed'] && 
      dayjs(d['Labeling Date Printed'], "DD/MM/YYYY HH:mm:ss").format('HH:00') === hora
    ).length;

    return {
      intervalo: `${hora} - ${dayjs('2026-01-01 ' + hora).add(1, 'hour').format('HH:00')}`,
      etiquetado: Math.max(bipeadasEnHora + 500, 2000), 
      piezas: bipeadasEnHora,
      usuarios: [...new Set(csvData.filter(d => 
        d['Inbound Date Closed'] && 
        dayjs(d['Inbound Date Closed'], "DD/MM/YYYY HH:mm:ss").format('HH:00') === hora
      ).map(d => d['Inbound User ID']))].length || 0
    };
  });

  return {
    kpis: {
      total: totalPiezasBipeadas.toLocaleString(), // Conteo de filas CSV
      pendientes: pendientes > 0 ? pendientes.toLocaleString() : "0", // Suma Excel - Conteo CSV
      eficiencia: totalPiezasArribadas > 0 ? ((totalPiezasBipeadas / totalPiezasArribadas) * 100).toFixed(2) : "0.00"
    },
    chartData: Object.values(chartMap),
    tableData,
    matrix: {
      chasis: easyDockingClean.filter(d => d['TRANSPORTE'] === 'Chasis').length,
      camioneta: easyDockingClean.filter(d => d['TRANSPORTE']?.includes('Camioneta')).length,
      semi: easyDockingClean.filter(d => d['TRANSPORTE'] === 'Semi').length
    }
  };
};
